class Solution(object):
    def maxMoves(self, grid):
        m, n = len(grid), len(grid[0])
        # dp[r][c] = max moves to reach cell (r, c)
        # Initialize first column as reachable
        dp = [[-1]*n for _ in range(m)]
        for r in range(m):
            dp[r][0] = 0

        ans = 0
        for c in range(1, n):
            for r in range(m):
                for dr in [-1, 0, 1]:
                    pr = r + dr
                    pc = c - 1
                    if 0 <= pr < m and dp[pr][pc] != -1:
                        if grid[r][c] > grid[pr][pc]:
                            dp[r][c] = max(dp[r][c], dp[pr][pc] + 1)
                if dp[r][c] != -1:
                    ans = max(ans, dp[r][c])
        return ans
